// src/pages/SubjectSelection.jsx
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getSubjectsForSemester } from '../services/api';
import { getCourseById } from '../config/config';

const SubjectSelection = () => {
  const { courseId, yearId, semId } = useParams();
  const navigate = useNavigate();
  const [subjects, setSubjects] = useState([]);
  const [course, setCourse] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSubjectsData();
  }, [courseId, yearId, semId]);

  const fetchSubjectsData = async () => {
    try {
      // Get course info from config
      const courseData = getCourseById(courseId);
      setCourse(courseData);

      // Try to get subjects from API
      let subjectsData;
      try {
        subjectsData = await getSubjectsForSemester(courseId, parseInt(yearId), parseInt(semId));
      } catch (apiError) {
        console.log('API failed, using fallback data');
        // Fallback subjects data
        subjectsData = [
          { id: 1, name: 'Mathematics-I', code: 'MATH101', credits: 4 },
          { id: 2, name: 'Physics', code: 'PHY101', credits: 4 },
          { id: 3, name: 'Chemistry', code: 'CHE101', credits: 4 },
          { id: 4, name: 'Programming in C', code: 'CSE101', credits: 3 },
          { id: 5, name: 'English', code: 'ENG101', credits: 2 },
        ];
      }

      setSubjects(subjectsData);
    } catch (error) {
      console.error('Error fetching subjects:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubjectClick = (subjectId) => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semId}/subject/${subjectId}`);
  };

  const handleBack = () => {
    navigate(`/course/${courseId}/year/${yearId}`);
  };

  if (loading) {
    return (
      <div style={styles.loadingContainer}>
        <div style={styles.loadingSpinner}></div>
        <p>Loading subjects...</p>
      </div>
    );
  }

  if (!course) {
    return (
      <div style={styles.errorContainer}>
        <h3>Course not found!</h3>
        <button onClick={handleBack} style={styles.backButton}>
          ← Back to Semesters
        </button>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      {/* Header */}
      <div style={styles.header}>
        <button onClick={handleBack} style={styles.backButton}>
          ← Back to Semesters
        </button>
        <div style={styles.pageHeader}>
          <h1 style={styles.title}>
            <span style={styles.courseIcon}>{course.icon}</span>
            {course.name} - Year {yearId} - Sem {semId}
          </h1>
          <p style={styles.subtitle}>Select a subject to view study materials</p>
        </div>
      </div>

      {/* Subjects Grid */}
      <div style={styles.subjectsGrid}>
        {subjects.map((subject) => (
          <div
            key={subject.id}
            style={styles.subjectCard}
            onClick={() => handleSubjectClick(subject.id)}
          >
            <div style={styles.subjectHeader}>
              <div style={styles.subjectIcon}>📖</div>
              <div style={styles.subjectCode}>{subject.code}</div>
            </div>
            
            <h3 style={styles.subjectName}>{subject.name}</h3>
            <p style={styles.subjectCredits}>{subject.credits} Credits</p>
            
            <div style={styles.materialsPreview}>
              <span style={styles.materialBadge}>Syllabus</span>
              <span style={styles.materialBadge}>Notes</span>
              <span style={styles.materialBadge}>PYQs</span>
              <span style={styles.materialBadge}>Lab Manual</span>
            </div>
            
            <button style={styles.viewButton}>
              View Materials →
            </button>
          </div>
        ))}
      </div>

      {/* Semester Info */}
      <div style={styles.semesterInfo}>
        <h3>📚 Semester {semId} Information</h3>
        <p>
          Total Subjects: {subjects.length} • 
          Total Credits: {subjects.reduce((sum, sub) => sum + sub.credits, 0)} • 
          Estimated Materials: {subjects.length * 15}+
        </p>
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem 1rem',
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
  },
  header: {
    marginBottom: '2rem'
  },
  backButton: {
    padding: '0.75rem 1.5rem',
    background: '#4f46e5',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    fontSize: '1rem',
    marginBottom: '1rem',
    display: 'inline-block',
    transition: 'all 0.3s',
    '&:hover': {
      background: '#4338ca',
      transform: 'translateX(-5px)'
    }
  },
  pageHeader: {
    background: 'white',
    padding: '2rem',
    borderRadius: '15px',
    textAlign: 'center',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)'
  },
  courseIcon: {
    fontSize: '2rem',
    marginRight: '0.5rem',
    verticalAlign: 'middle'
  },
  title: {
    fontSize: '2rem',
    marginBottom: '0.5rem',
    color: '#1f2937'
  },
  subtitle: {
    color: '#6b7280',
    fontSize: '1.1rem'
  },
  subjectsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '1.5rem',
    marginBottom: '2rem'
  },
  subjectCard: {
    background: 'white',
    padding: '1.5rem',
    borderRadius: '12px',
    cursor: 'pointer',
    transition: 'all 0.3s',
    border: '2px solid transparent',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)',
    '&:hover': {
      transform: 'translateY(-5px)',
      borderColor: '#4f46e5',
      boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
    }
  },
  subjectHeader: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '1rem'
  },
  subjectIcon: {
    fontSize: '2rem'
  },
  subjectCode: {
    background: '#e0e7ff',
    color: '#4f46e5',
    padding: '0.25rem 0.75rem',
    borderRadius: '12px',
    fontSize: '0.8rem',
    fontWeight: '500'
  },
  subjectName: {
    fontSize: '1.25rem',
    marginBottom: '0.5rem',
    color: '#1f2937'
  },
  subjectCredits: {
    color: '#6b7280',
    marginBottom: '1rem',
    fontSize: '0.9rem'
  },
  materialsPreview: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '0.5rem',
    margin: '1rem 0'
  },
  materialBadge: {
    background: '#f3f4f6',
    color: '#4b5563',
    padding: '0.25rem 0.75rem',
    borderRadius: '12px',
    fontSize: '0.75rem'
  },
  viewButton: {
    marginTop: '1rem',
    padding: '0.75rem',
    width: '100%',
    background: 'linear-gradient(90deg, #f59e0b, #fbbf24)',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    fontSize: '0.9rem',
    fontWeight: '500'
  },
  semesterInfo: {
    background: 'white',
    padding: '1.5rem',
    borderRadius: '12px',
    textAlign: 'center',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)',
    color: '#6b7280'
  },
  loadingContainer: {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
  },
  loadingSpinner: {
    width: '50px',
    height: '50px',
    border: '5px solid #e2e8f0',
    borderTop: '5px solid #4f46e5',
    borderRadius: '50%',
    animation: 'spin 1s linear infinite',
    marginBottom: '1rem'
  },
  errorContainer: {
    textAlign: 'center',
    padding: '3rem',
    minHeight: '100vh',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
  }
};

// ✅ MUST HAVE THIS LINE:
export default SubjectSelection;
